var e=[{id:`L2_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`......작전 성공.`,JPN:`……作戦成功。`,ENG:`...Mission accomplished.`,TWN:`作戰成功。`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`호구들이 미끼를 물었다.`,JPN:`バカどもが罠にかかった。`,ENG:`Those morons took the bait.`,TWN:`那些冤大頭果然上當了。`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`제대로 확인한 거 맞아?`,JPN:`それ、ちゃんと確認したのか？`,ENG:`You sure about that?`,TWN:`妳有真的看到嗎？`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`당연하지.`,JPN:`当然よ。`,ENG:`Of course I am.`,TWN:`當然。`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`내가 너처럼 안구에 비계라도 낀 줄 알아?`,JPN:`私の目はあんたみたいにくもってないもの。`,ENG:`I'm not an idiot like you...`,TWN:`妳以為我和妳一樣，眼球上都長滿肥肉嗎？`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`그 말 내 앞에 나와서 해 보지 그래, 겁쟁이 자식아.`,JPN:`あーん？　俺の前でもう一度言ってみろよ、このイワシが！`,ENG:`You wanna say that to my face? You coward...`,TWN:`有種站到我面前說啊，膽小鬼。`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`그렇게 꽁꽁 싸매고 기어 다니면서 뭐 똑바로 하는 게 있겠냐? `,JPN:`厚着して這いつくばってるくせに、まともにできることなんかあるのか？ `,ENG:`I doubt you can do a single thing right when you're crawling around all day with that gear. `,TWN:`平平趴在地上的妳又能做什麼？`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`......이 망할 자식이!`,JPN:`……てめえ！`,ENG:`You little twerp!`,TWN:`妳這該死的混蛋！`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`이거 진짜 맞추려고 쏜 거지?!`,JPN:`これ本気で当てるつもりで撃ったな！？`,ENG:`You were actually aiming for me, weren't you?!`,TWN:`妳是故意的吧？！`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`당장 내려와! 박살내 주마!`,JPN:`今すぐ下りて来いよ！ぶっ殺してやる！`,ENG:`Get your butt down here right now! I'm going to destroy you!`,TWN:`立刻給我下來！看我不揍爆妳！`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`그만, 그만. 싸우지 말라고.`,JPN:`はいはい、やめて、ケンカしないでよ。`,ENG:`Stop it, you guys. Quit fighting.`,TWN:`好了，好了，別吵了。`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`KIMSOBIN_ALT_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L19_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`이제부터가 진짜니까.`,JPN:`ここからが本番なんだから。`,ENG:`It's time to get serious.`,TWN:`現在要開始來真的了。`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`KIMSOBIN_ALT_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`하지만......!`,JPN:`でも……！`,ENG:`But...!`,TWN:`但是！`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`조용히 하라고 했잖아.`,JPN:`静かに、って言ったよね。`,ENG:`I said quiet...`,TWN:`我叫妳安靜。`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`KIMSOBIN_ALT_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L25_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`아니면, 내 말이 이해가 안 됐을까?`,JPN:`それとも、言ってる意味がわからないのかな？`,ENG:`Or did I not make myself clear...?`,TWN:`還是說，妳聽不懂我說的話？`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`KIMSOBIN_ALT_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L27_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`......아, 알았어.`,JPN:`わ……わかったよ。`,ENG:`Oh... Okay.`,TWN:`知……知道了。`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};